import{_ as s,c as n,o as a,U as e}from"./chunks/framework.9QHaLlVJ.js";const p="/assets/image-20211118175919565.YCvVMf40.png",c="/assets/image-20211118180006951.x7aOgoAs.png",h=JSON.parse('{"title":"可重入锁","description":null,"frontmatter":{"lang":"zh-CN","title":"可重入锁","description":null},"headers":[],"relativePath":"doc/编程语言/Go/实战/可重入锁/Reentrant lock.md","filePath":"packages/doc/src/编程语言/Go/实战/可重入锁/Reentrant lock.md","lastUpdated":1704297641000}'),l={name:"doc/编程语言/Go/实战/可重入锁/Reentrant lock.md"},o=e('<h2 id="什么是可重入锁" tabindex="-1">什么是可重入锁 <a class="header-anchor" href="#什么是可重入锁" aria-label="Permalink to &quot;什么是可重入锁&quot;">​</a></h2><p>之前写过<code>java</code>的同学对这个概念应该了如指掌，可重入锁又称为递归锁，是指在同一个线程在外层方法获取锁的时候，在进入该线程的内层方法时会自动获取锁，不会因为之前已经获取过还没释放而阻塞。美团技术团队的一篇关于锁的文章当中针对可重入锁进行了举例：</p><p>假设现在有多个村民在水井排队打水，有管理员正在看管这口水井，村民在打水时，管理员允许锁和同一个人的多个水桶绑定，这个人用多个水桶打水时，第一个水桶和锁绑定并打完水之后，第二个水桶也可以直接和锁绑定并开始打水，所有的水桶都打完水之后打水人才会将锁还给管理员。这个人的所有打水流程都能够成功执行，后续等待的人也能够打到水。这就是可重入锁。</p><p>下图摘自美团技术团队分享的文章：</p><p><img src="'+p+'" alt="image-20211118175919565"></p><p>如果是非可重入锁，，此时管理员只允许锁和同一个人的一个水桶绑定。第一个水桶和锁绑定打完水之后并不会释放锁，导致第二个水桶不能和锁绑定也无法打水。当前线程出现死锁，整个等待队列中的所有线程都无法被唤醒。</p><p>下图依旧摘自美团技术团队分享的文章：</p><p><img src="'+c+`" alt="image-20211118180006951"></p><h2 id="用go实现可重入锁" tabindex="-1">用<code>Go</code>实现可重入锁 <a class="header-anchor" href="#用go实现可重入锁" aria-label="Permalink to &quot;用\`Go\`实现可重入锁&quot;">​</a></h2><p>既然我们想自己实现一个可重入锁，那我们就要了解<code>java</code>中可重入锁是如何实现的，查看了<code>ReentrantLock</code>的源码，大致实现思路如下：</p><p><code>ReentrantLock</code>继承了父类<code>AQS</code>，其父类<code>AQS</code>中维护了一个同步状态<code>status</code>来计数重入次数，<code>status</code>初始值为<code>0</code>，当线程尝试获取锁时，可重入锁先尝试获取并更新<code>status</code>值，如果<code>status == 0</code>表示没有其他线程在执行同步代码，则把<code>status</code>置为<code>1</code>，当前线程开始执行。如果<code>status != 0</code>，则判断当前线程是否是获取到这个锁的线程，如果是的话执行<code>status+1</code>，且当前线程可以再次获取锁。释放锁时，可重入锁同样先获取当前<code>status</code>的值，在当前线程是持有锁的线程的前提下。如果<code>status-1 == 0</code>，则表示当前线程所有重复获取锁的操作都已经执行完毕，然后该线程才会真正释放锁。</p><p>总结一下实现一个可重入锁需要这两点：</p><ul><li>记住持有锁的线程</li><li>统计重入的次数</li></ul><p>统计重入的次数很容易实现，接下来我们考虑一下怎么实现记住持有锁的线程？</p><p>我们都知道<code>Go</code>语言最大的特色就是从语言层面支持并发，<code>Goroutine</code>是<code>Go</code>中最基本的执行单元，每一个<code>Go</code>程序至少有一个<code>Goroutine</code>，主程序也是一个<code>Goroutine</code>，称为主<code>Goroutine</code>，当程序启动时，他会自动创建。每个<code>Goroutine</code>也是有自己唯一的编号，这个编号只有在<code>panic</code>场景下才会看到，<code>Go语言</code>却刻意没有提供获取该编号的接口，官方给出的原因是为了避免滥用。但是我们还是通过一些特殊手段来获取<code>Goroutine ID</code>的，可以使用<code>runtime.Stack</code>函数输出当前栈帧信息，然后解析字符串获取<code>Goroutine ID</code>，具体代码可以参考开源项目 - goid。</p><p>因为<code>go</code>语言中的<code>Goroutine</code>有<code>Goroutine ID</code>，那么我们就可以通过这个来记住当前的线程，通过这个来判断是否持有锁，就可以了，因此我们可以定义如下结构体：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>type ReentrantLock struct {</span></span>
<span class="line"><span> lock *sync.Mutex</span></span>
<span class="line"><span> cond *sync.Cond</span></span>
<span class="line"><span> recursion int32</span></span>
<span class="line"><span> host     int64</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>其实就是包装了<code>Mutex</code>锁，使用<code>host</code>字段记录当前持有锁的<code>goroutine id</code>，使用<code>recursion</code>字段记录当前<code>goroutine</code>的重入次数。这里有一个特别要说明的就是<code>sync.Cond</code>，使用<code>Cond</code>的目的是，当多个<code>Goroutine</code>使用相同的可重入锁时，通过<code>cond</code>可以对多个协程进行协调，如果有其他协程正在占用锁，则当前协程进行阻塞，直到其他协程调用释放锁。具体<code>sync.Cond</code>的使用大家可以参考我之前的一篇文章：<a href="https://mp.weixin.qq.com/s?__biz=MzIzMDU0MTA3Nw==&amp;mid=2247484580&amp;idx=1&amp;sn=9dc984cc13c7291972acf072dc7dea42&amp;scene=21#wechat_redirect" target="_blank" rel="noreferrer">源码剖析sync.cond(条件变量的实现机制）</a>。</p><ul><li>构造函数</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>func NewReentrantLock()  sync.Locker{</span></span>
<span class="line"><span> res := &amp;ReentrantLock{</span></span>
<span class="line"><span>  lock: new(sync.Mutex),</span></span>
<span class="line"><span>  recursion: 0,</span></span>
<span class="line"><span>  host: 0,</span></span>
<span class="line"><span> }</span></span>
<span class="line"><span> res.cond = sync.NewCond(res.lock)</span></span>
<span class="line"><span> return res</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><ul><li><code>Lock</code></li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>func (rt *ReentrantLock) Lock()  {</span></span>
<span class="line"><span> id := GetGoroutineID()</span></span>
<span class="line"><span> rt.lock.Lock()</span></span>
<span class="line"><span> defer rt.lock.Unlock()</span></span>
<span class="line"><span></span></span>
<span class="line"><span> if rt.host == id{</span></span>
<span class="line"><span>  rt.recursion++</span></span>
<span class="line"><span>  return</span></span>
<span class="line"><span> }</span></span>
<span class="line"><span></span></span>
<span class="line"><span> for rt.recursion != 0{</span></span>
<span class="line"><span>  rt.cond.Wait()</span></span>
<span class="line"><span> }</span></span>
<span class="line"><span> rt.host = id</span></span>
<span class="line"><span> rt.recursion = 1</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>这里逻辑比较简单，大概解释一下：</p><p>首先我们获取当前<code>Goroutine</code>的<code>ID</code>，然后我们添加互斥锁锁住当前代码块，保证并发安全，如果当前<code>Goroutine</code>正在占用锁，则增加<code>resutsion</code>的值，记录当前线程加锁的数量，然后返回即可。如果当前<code>Goroutine</code>没有占用锁，则判断当前可重入锁是否被其他<code>Goroutine</code>占用，如果有其他<code>Goroutine</code>正在占用可重入锁，则调用<code>cond.wait</code>方法进行阻塞，直到其他协程释放锁。</p><ul><li><code>Unlock</code></li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>func (rt *ReentrantLock) Unlock()  {</span></span>
<span class="line"><span> rt.lock.Lock()</span></span>
<span class="line"><span> defer rt.lock.Unlock()</span></span>
<span class="line"><span></span></span>
<span class="line"><span> if rt.recursion == 0 || rt.host != GetGoroutineID() {</span></span>
<span class="line"><span>  panic(fmt.Sprintf(&quot;the wrong call host: (%d); current_id: %d; recursion: %d&quot;, rt.host,GetGoroutineID(),rt.recursion))</span></span>
<span class="line"><span> }</span></span>
<span class="line"><span></span></span>
<span class="line"><span> rt.recursion--</span></span>
<span class="line"><span> if rt.recursion == 0{</span></span>
<span class="line"><span>  rt.cond.Signal()</span></span>
<span class="line"><span> }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>大概解释如下：</p><p>首先我们添加互斥锁锁住当前代码块，保证并发安全，释放可重入锁时，如果非持有锁的<code>Goroutine</code>释放锁则会导致程序出现<code>panic</code>，这个一般是由于用户用法错误导致的。如果当前<code>Goroutine</code>释放了锁，则调用<code>cond.Signal</code>唤醒其他协程。</p><p>测试例子就不在这里贴了，代码已上传<code>github</code>:<a href="https://github.com/asong2020/Golang_Dream/tree/master/code_demo/reentrantLock%EF%BC%8C%E6%AC%A2%E8%BF%8Estar%E3%80%82" target="_blank" rel="noreferrer">https://github.com/asong2020/Golang_Dream/tree/master/code_demo/reentrantLock，欢迎star。</a></p><h2 id="为什么go语言中没有可重入锁" tabindex="-1">为什么<code>Go</code>语言中没有可重入锁 <a class="header-anchor" href="#为什么go语言中没有可重入锁" aria-label="Permalink to &quot;为什么\`Go\`语言中没有可重入锁&quot;">​</a></h2><p>这问题的答案，我在：<a href="https://stackoverflow.com/questions/14670979/recursive-locking-in-go#14671462%EF%BC%8C%E8%BF%99%E9%87%8C%E6%89%BE%E5%88%B0%E4%BA%86%E7%AD%94%E6%A1%88%E3%80%82%60Go%60%E8%AF%AD%E8%A8%80%E7%9A%84%E5%8F%91%E6%98%8E%E8%80%85%E8%AE%A4%E4%B8%BA%EF%BC%8C%E5%A6%82%E6%9E%9C%E5%BD%93%E4%BD%A0%E7%9A%84%E4%BB%A3%E7%A0%81%E9%9C%80%E8%A6%81%E9%87%8D%E5%85%A5%E9%94%81%E6%97%B6%EF%BC%8C%E9%82%A3%E5%B0%B1%E8%AF%B4%E6%98%8E%E4%BD%A0%E7%9A%84%E4%BB%A3%E7%A0%81%E6%9C%89%E9%97%AE%E9%A2%98%E4%BA%86%EF%BC%8C%E6%88%91%E4%BB%AC%E6%AD%A3%E5%B8%B8%E5%86%99%E4%BB%A3%E7%A0%81%E6%97%B6%EF%BC%8C%E4%BB%8E%E5%85%A5%E5%8F%A3%E5%87%BD%E6%95%B0%E5%BC%80%E5%A7%8B%EF%BC%8C%E6%89%A7%E8%A1%8C%E7%9A%84%E5%B1%82%E6%AC%A1%E9%83%BD%E6%98%AF%E4%B8%80%E5%B1%82%E5%B1%82%E5%BE%80%E4%B8%8B%E7%9A%84%EF%BC%8C%E5%A6%82%E6%9E%9C%E6%9C%89%E4%B8%80%E4%B8%AA%E9%94%81%E9%9C%80%E8%A6%81%E5%85%B1%E4%BA%AB%E7%BB%99%E5%87%A0%E4%B8%AA%E5%87%BD%E6%95%B0%EF%BC%8C%E9%82%A3%E4%B9%88%E5%B0%B1%E5%9C%A8%E8%B0%83%E7%94%A8%E8%BF%99%E5%87%A0%E4%B8%AA%E5%87%BD%E6%95%B0%E7%9A%84%E4%B8%8A%E9%9D%A2%EF%BC%8C%E7%9B%B4%E6%8E%A5%E5%8A%A0%E4%B8%8A%E4%BA%92%E6%96%A5%E9%94%81%E5%B0%B1%E5%A5%BD%E4%BA%86%EF%BC%8C%E4%B8%8D%E9%9C%80%E8%A6%81%E5%9C%A8%E6%AF%8F%E4%B8%80%E4%B8%AA%E5%87%BD%E6%95%B0%E9%87%8C%E9%9D%A2%E9%83%BD%E6%B7%BB%E5%8A%A0%E9%94%81%EF%BC%8C%E5%86%8D%E5%8E%BB%E9%87%8A%E6%94%BE%E9%94%81%E3%80%82" target="_blank" rel="noreferrer">https://stackoverflow.com/questions/14670979/recursive-locking-in-go#14671462，这里找到了答案。\`Go\`语言的发明者认为，如果当你的代码需要重入锁时，那就说明你的代码有问题了，我们正常写代码时，从入口函数开始，执行的层次都是一层层往下的，如果有一个锁需要共享给几个函数，那么就在调用这几个函数的上面，直接加上互斥锁就好了，不需要在每一个函数里面都添加锁，再去释放锁。</a></p><p>举个例子，假设我们现在一段这样的代码：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>func F() {</span></span>
<span class="line"><span> mu.Lock()</span></span>
<span class="line"><span> //... do some stuff ...</span></span>
<span class="line"><span> G()</span></span>
<span class="line"><span> //... do some more stuff ...</span></span>
<span class="line"><span> mu.Unlock()</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>func G() {</span></span>
<span class="line"><span> mu.Lock()</span></span>
<span class="line"><span> //... do some stuff ...</span></span>
<span class="line"><span> mu.Unlock()</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>函数<code>F()</code>和<code>G()</code>使用了相同的互斥锁，并且都在各自函数内部进行了加锁，这要使用就会出现死锁，使用<strong>可重入锁</strong>可以解决这个问题，但是更好的方法是改变我们的代码结构，我们进行分解代码，如下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>func call(){</span></span>
<span class="line"><span>  F()</span></span>
<span class="line"><span>  G()</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>func F() {</span></span>
<span class="line"><span>      mu.Lock()</span></span>
<span class="line"><span>      ... do some stuff</span></span>
<span class="line"><span>      mu.Unlock()</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>func g() {</span></span>
<span class="line"><span>     ... do some stuff ...</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>func G() {</span></span>
<span class="line"><span>     mu.Lock()</span></span>
<span class="line"><span>     g()</span></span>
<span class="line"><span>     mu.Unlock()</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><p>这样不仅避免了死锁，而且还对代码进行了解耦。这样的代码按照作用范围进行了分层，就像金字塔一样，上层调用下层的函数，越往上作用范围越大；各层有自己的锁。</p><p>总结：<code>Go</code>语言中完全没有必要使用可重入锁，如果我们发现我们的代码要使用到可重入锁了，那一定是我们写的代码有问题了，请检查代码结构，修改他！！！</p>`,37),r=[o];function i(t,d,u,b,m,E){return a(),n("div",null,r)}const A=s(l,[["render",i]]);export{h as __pageData,A as default};
